+    local procedure IsItemFullyCommittedAsComponent(var Item: Record Item): Boolean
+    var
+        ProdOrderComp: Record "Prod. Order Component";
+    begin
+        // Check if item is only used as component in released/finished production orders and all instances are fully reserved
+        if not ProdOrderComp.FindLinesWithItemToPlan(Item, true) then
+            exit(false); // No production order components for this item
+
+        repeat
+            ProdOrderComp.CalcFields("Reserved Qty. (Base)");
+            // If any component is not fully reserved, or is not from a released/finished order, we need to plan
+            if (ProdOrderComp."Remaining Qty. (Base)" <> ProdOrderComp."Reserved Qty. (Base)") or
+               not (ProdOrderComp.Status in [ProdOrderComp.Status::Released, ProdOrderComp.Status::Finished])
+            then
+                exit(false);
+        until ProdOrderComp.Next() = 0;
+
+        // All components are from released/finished orders and fully reserved
+        exit(true);
+    end;
